#include <stdio.h>
#include <stdbool.h>

bool isSub(const char *a, const char *b) {
    int i = 0, j = 0;
    while (a[i] && b[j]) {
        if (a[i] == b[j]) i++;
        j++;
    }
    return a[i] == '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char M[25001], W[25001];
        scanf("%s %s", M, W);
        if (isSub(M, W) || isSub(W, M))
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

