#include <bits/stdc++.h>
using namespace std;

bool isSub(const string &a, const string &b) {
    size_t i = 0, j = 0;
    while (i < a.size() && j < b.size()) {
        if (a[i] == b[j]) ++i;
        ++j;
    }
    return i == a.size();
}

int main() {
